const fs = require('fs');

// Récupérer TOUS les items
const data = $input.all().map(item => item.json);

// Écrire le tableau complet
fs.writeFileSync(
  'C:\\hicham\\scripts\\match_article_br\\input_temp.json',
  JSON.stringify(data, null, 2),
  'utf-8'
);

// Retourner tous les items pour la suite du workflow
return $input.all();

// Mode: Run Once for All Items
const items = $input.all();
const results = [];

items.forEach((item, index) => {
  const stdout = item.json.stdout;

  if (!stdout || stdout.trim() === '') {
    results.push({
      json: { error: "stdout vide", raw: item.json },
      pairedItem: { item: index }
    });
    return;
  }

  let parsed;
  try {
    parsed = JSON.parse(stdout);
  } catch (e) {
    results.push({
      json: { error: "JSON parse error: " + e.message, raw: stdout.slice(0, 300) },
      pairedItem: { item: index }
    });
    return;
  }

  // Normalise en tableau
  const lines = Array.isArray(parsed) ? parsed : [parsed];

  for (const line of lines) {
    results.push({
      json: line,
      pairedItem: { item: index }   // ← relie chaque ligne à son item source
    });
  }
});

return results;

