          numero_bc: bc,
          statut_bc: statut_bc,
          fournisseur_nom: data.fournisseur_nom,
          base_ht: data.base_ht,
          tva_montant: data.tva_montant,
          total_ttc: data.total_ttc,
          lignes: [ligne]
        }
      });
    }
  }
}
return results;

// Node Code n8n - Mode: "Run Once for All Items"
const items = $input.all();

// ── Regrouper les lignes par numero_bl ─
const blGroups = {};
for (const item of items) {
  const data = item.json.input;
  const bl = data.numero_bl;
  if (!bl || bl === 'undefined') continue; // ignorer les lignes sans BL

  // ── Ne garder que les lignes dont le statut n'est pas 'not_matched' ─
  if (item.json.statut === 'not_matched') continue;

  if (!blGroups[bl]) {
    blGroups[bl] = {
      numero_bl: bl,
      numero_bc: data.POHNUM_0,
      code_fournisseur: data.BPSNUM_0,
      date_bc: data.ORDDAT_0,
      lignes: []
    };
  }
  blGroups[bl].lignes.push({
    designation_ocr:        data.designation_ocr,
    reference_ocr:          data.reference_ocr,
    reference_ocr_norm:     data.reference_ocr_norm,
    quantite_ocr:           data.quantite_ocr,
    prix_unitaire_ocr:      data.prix_unitaire_ocr,
    montant_ht_ocr:         data.montant_ht_ocr,
    skip_numerique_reason:  data.skip_numerique_reason,
    statut:                 item.json.statut,
    score:                  item.json.score,
    nb_bc_candidats:        item.json.nb_bc_candidats,
    bc_candidats:           item.json.bc_candidats,
    // ── Code article et désignation matchés dans X3 ─
    code_article:           item.json.itmref_found,
    designation_x3:         item.json.itmdes_found,
    marque_x3:               item.json.details_x3?.XMARQ_0 ?? null
  });
}

// ── Construire un item Redis par BL ─
const groupesValides = Object.values(blGroups).filter(group => group.lignes.length > 0);

const toRedis = groupesValides.map(group => {
  const redisData = {
    numero_bl: group.numero_bl,
    numero_bc: group.numero_bc,
    code_fournisseur: group.code_fournisseur,
    date_bc: group.date_bc,
    nb_lignes_non_matchees: group.lignes.length,
    lignes: group.lignes,
    date_creation: new Date().toISOString(),
    statut_global: 'en_attente_resolution'
  };
  return {
    json: {
      redis_key: `bl_non_matched:${group.numero_bl}`,
      redis_value: JSON.stringify(redisData),
      redis_ttl: 300,
      user_data: redisData
    }
  };
});

// ── Item supplémentaire : regroupement global de toutes les données stockées dans Redis ─
const dateCreationGlobale = new Date().toISOString();
const resumeGlobal = {
  nb_bl_total: groupesValides.length,
  nb_lignes_total: groupesValides.reduce((sum, g) => sum + g.lignes.length, 0),
  bls: groupesValides.map(g => g.numero_bl),
  date_creation: dateCreationGlobale
};

toRedis.push({
  json: {
    redis_key: `bl_non_matched:resume:${dateCreationGlobale}`,
    redis_value: JSON.stringify(resumeGlobal),
    redis_ttl: 300,
    user_data: resumeGlobal
  }
});

return toRedis;

// Node Code n8n - Mode: "Run Once for All Items"
// Le champ Redis contenant le JSON stringifié s'appelle "propertyName"

const items = $input.all();
const result = [];

for (const item of items) {
  const rawValue = item.json.propertyName;

  if (!rawValue) continue;

  let blData;
  try {
    blData = typeof rawValue === 'string' ? JSON.parse(rawValue) : rawValue;
  } catch (e) {
    result.push({
      json: {
        error: `Erreur de parsing JSON: ${e.message}`,
        raw: rawValue
      }
    });
    continue;
  }

  // ── Filtrer uniquement les lignes avec statut "non_matched" ─
  const lignesNonMatchees = (blData.lignes || []).filter(
    ligne => ligne.statut !== 'non_matched' || (ligne.score !== null)
  );

  // ── Créer un item n8n par ligne non matchée, avec le contexte du BL ─
  for (const ligne of lignesNonMatchees) {
    result.push({
      json: {
        // Contexte du BL/BC
        numero_bl: blData.numero_bl,
        numero_bc: blData.numero_bc,
        code_fournisseur: blData.code_fournisseur,
        date_bc: blData.date_bc,
        date_creation: blData.date_creation,
        statut_global: blData.statut_global,

        // Détails de la ligne non matchée
        designation_ocr: ligne.designation_ocr,
        reference_ocr: ligne.reference_ocr,
        reference_ocr_norm: ligne.reference_ocr_norm,
        quantite_ocr: ligne.quantite_ocr,
        prix_unitaire_ocr: ligne.prix_unitaire_ocr,
        montant_ht_ocr: ligne.montant_ht_ocr,
        skip_numerique_reason: ligne.skip_numerique_reason,
        statut: ligne.statut,
        score: ligne.score,
        code_article: ligne.code_article,
        nb_bc_candidats: ligne.nb_bc_candidats,
        bc_candidats: ligne.bc_candidats
      }
    });
  }
}

return result;

parameters.text:
=Voici une liste de lignes à analyser. Pour CHAQUE ligne, identifie LEQUEL des candidats ERP proposés (candidats_erp) correspond réellement à la désignation fournisseur (designation_ocr), en appliquant les règles du system prompt.

Lignes à analyser :
{{ JSON.stringify($json.data.map((d, i) => ({
  index: i,
  designation_ocr: d.designation_ocr,
  numero_bc: d.numero_bc,
  numero_bl: d.numero_bl,
  quantite_ocr: d.quantite_ocr,
  candidats_erp: d.erp_candidates
}))) }}

Pour chaque ligne, choisis le candidat de candidats_erp le plus cohérent sémantiquement et techniquement avec designation_ocr, en respectant strictement les règles d'unicité et d'absence de match du system prompt.

Retourne un OBJET JSON unique avec exactement cette forme :
{
  "lignes": [
    { "index": ..., "designation_ocr": ..., "numero_bc":...,"numero_bl":...,"quantite_ocr:...",'"code_article_erp": ..., "designation_erp": ... }
  ]
}
Le tableau "lignes" doit contenir un résultat par ligne d'entrée, dans le même ordre que "index".

