// Node Code n8n - Mode: "Run Once for All Items"
// Regroupe les candidats ERP par designation_ocr (même OCR = plusieurs ITMREF possibles du même BC)

const items = $input.all();
const groupes = {};

for (const item of items) {
  const d = item.json;
  const key = `${d.designation_ocr}`;

  if (!groupes[key]) {
    groupes[key] = {
      designation_ocr: d.designation_ocr,
      numero_bc: d.POHNUM_0,
      numero_bl: d.numero_bl,     
      quantite_ocr: d.quantite_ocr,
      erp_candidates: []
    };
  }

  // Éviter les doublons de candidats
  const dejaPresent = groupes[key].erp_candidates.some(c => c.itmref === d.ITMREF_0);
  if (!dejaPresent) {
    groupes[key].erp_candidates.push({
      itmref: d.ITMREF_0,
      designation: d.ITMDES1_0
    });
  }
}

return [{ json: { data: Object.values(groupes) } }];

// Node Code n8n - Mode: "Run Once for All Items"
// Éclate chaque ligne de output.lignes en un item n8n distinct

const items = $input.all();
const result = [];

for (const item of items) {
  const output = item.json.output;

  if (!output || !Array.isArray(output.lignes)) {
    result.push({
      json: {
        error: "Format inattendu : 'output.lignes' introuvable ou n'est pas un tableau",
        raw: item.json
      }
    });
    continue;
  }

  for (const ligne of output.lignes) {
    result.push({
      json: {
        index: ligne.index,
        designation_ocr: ligne.designation_ocr,
        numero_bc: ligne.numero_bc,
        numero_bl: ligne.numero_bl,
        quantite_ocr: ligne.quantite_ocr,
        code_article_erp: ligne.code_article_erp,
        designation_erp: ligne.designation_erp,
        match_trouve: ligne.code_article_erp !== null
      }
    });
  }
}

return result;

const items = $input.all();
const result = [];

for (const item of items) {
  const userData = item.json.user_data;
  const lignes = userData.lignes || [];

  for (const ligne of lignes) {
    result.push({
      json: {
        numero_bl: userData.numero_bl,
        numero_bc: userData.numero_bc,
        code_fournisseur: userData.code_fournisseur,
        date_bc: userData.date_bc,
        statut_global: userData.statut_global,
        ...ligne
      }
    });
  }
}

return result;
